if( page.variables.hideNewFeatures || page.variables.isAdmin || page.variables.isNonTech || ( components.addConfigValueFormNonSingleCheckboxSkipCMR.value|| components.addConfigValueFormNonSingle2CheckboxSkipCMR.value || components.updateConfigValueFormNonSingleCheckboxSkipCMR.value ||  components.updateConfigValueFormNonSingle2CheckboxSkipCMR.value|| components.deleteConfigValueFormNonSingleCheckboxSkipCMR.value || components.deleteConfigValueFormNonSingle2CheckboxSkipCMR.value)) {
  return true;
}

const tempConfigValues = page.variables.allConfigValues;
let listOfUpdates = [];
tempConfigValues.forEach(val => {
  const createdTime = val?.created_time?.seconds;
  const updatedTime = val?.updated_time?.seconds;

  if (typeof createdTime !== undefined) {
    listOfUpdates.push(createdTime);
  }
  if (typeof updatedTime !== undefined && createdTime !== updatedTime) {
    listOfUpdates.push(updatedTime);
  }
})
let noOfValuesUpdatedInLast1Hour = 0; 
let noOfValuesUpdatedInLast5Minutes = 0;
let firstUpdate = Number.MAX_SAFE_INTEGER;
const currentTime = new Date().getTime();
listOfUpdates.forEach(val => {
  const givenMaxTime = val*1000;
  // Calculate the difference in milliseconds
  const differenceInMilliseconds = currentTime - givenMaxTime;
  // Convert 1 hour to milliseconds
  const oneHourInMilliseconds = 60 * 60 * 1000;
  // Check if the difference is within 1 hour
  const isWithinOneHourTime = (differenceInMilliseconds > 0 && differenceInMilliseconds <= oneHourInMilliseconds);
  const fiveMinutesInMilliseconds = 5 * 60 * 1000;
  // Check if the difference is within 5 minutes
  const isWithinFiveMinutesTime = (differenceInMilliseconds > 0 && differenceInMilliseconds <= fiveMinutesInMilliseconds);
  if(isWithinOneHourTime) {
    firstUpdate = Math.min(firstUpdate, givenMaxTime);
    noOfValuesUpdatedInLast1Hour += 1;
  }
  if(isWithinFiveMinutesTime) {
    noOfValuesUpdatedInLast5Minutes += 1;
  }
})
const timeDifference = currentTime - firstUpdate;
// Check if more than 3 updates are made in last 1 hour if true, then allow this operation
if(noOfValuesUpdatedInLast1Hour >= 3 && (timeDifference > 0 && timeDifference > 300000 )) {
  return true;
}
if(noOfValuesUpdatedInLast5Minutes < 3) {
  return true;
} else {
  return false;
}
